import { Routes, Route, Link } from "react-router-dom";
import { useEffect, useState } from "react";
import ClassLeaderboard from "./components/ClassLeaderboard";
import Leaderboard from "./components/Leaderboard";
import PersonalGrowth from "./components/PersonalGrowth";
import UserSearch from "./components/UserSearch";
import Home from "./components/Home";

export default function App() {
  const [darkMode, setDarkMode] = useState(false);

  // Load saved theme on first render
  useEffect(() => {
    const savedTheme = localStorage.getItem("theme");
    if (savedTheme === "dark") {
      setDarkMode(true);
      document.documentElement.classList.add("dark");
    }
  }, []);

  // Toggle dark mode
  const toggleDarkMode = () => {
    const next = !darkMode;
    setDarkMode(next);

    if (next) {
      document.documentElement.classList.add("dark");
      localStorage.setItem("theme", "dark");
    } else {
      document.documentElement.classList.remove("dark");
      localStorage.setItem("theme", "light");
    }
  };

  return (
    /* ================= GLOBAL BACKGROUND (ADDED) ================= */
    <div className="min-h-screen bg-gradient-to-br from-indigo-600 via-purple-600 to-pink-600">
      {/* Overlay to keep content readable */}
      <div className="min-h-screen bg-black/40 backdrop-blur-xl text-gray-900 dark:text-gray-100 transition-colors">
        {/* ================= NAVBAR ================= */}
        <nav className="bg-white/90 dark:bg-gray-800/90 backdrop-blur shadow px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-6">
            <Link
              to="/"
              className="text-xl font-bold text-blue-600 dark:text-blue-400"
            >
              CPulse Tracker
            </Link>

            <Link
              to="/search"
              className="font-medium hover:text-blue-600 dark:hover:text-blue-400 transition"
            >
              Search
            </Link>

            <Link
              to="/class"
              className="font-medium hover:text-blue-600 dark:hover:text-blue-400 transition"
            >
              Class Leaderboard
            </Link>

            <Link
              to="/leaderboard"
              className="font-medium hover:text-blue-600 dark:hover:text-blue-400 transition"
            >
              Global Rank
            </Link>
          </div>

          {/* Dark mode toggle */}
          <button
            onClick={toggleDarkMode}
            className="px-4 py-2 rounded-lg bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 transition"
          >
            {darkMode ? "☀️ Light" : "🌙 Dark"}
          </button>
        </nav>

        {/* ================= MAIN CONTENT ================= */}
        <main className="max-w-6xl mx-auto p-6">
          <Routes>
            <Route path="/" element={<Home />} />

            {/* Search users */}
            <Route path="/search" element={<UserSearch />} />

            {/* Leaderboards */}
            <Route path="/leaderboard" element={<Leaderboard />} />
            <Route path="/class" element={<ClassLeaderboard />} />

            {/* Personal growth */}
            <Route
              path="/growth/:username/:platform"
              element={<PersonalGrowth />}
            />

            {/* Fallback */}
            <Route
              path="*"
              element={
                <div className="text-center text-gray-300 mt-20">
                  <p className="text-lg">Page not found</p>
                </div>
              }
            />
          </Routes>
        </main>
      </div>
    </div>
  );
}
